request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" .
  OPTIONAL { ?model bbo:name ?modelName . }
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelId ?originalId ?normId ?modelName WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model bbo:name ?modelName . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "5ee15f85") || 
         CONTAINS(LCASE(STR(?originalId)), "5ee15f85") || 
         CONTAINS(LCASE(STR(?normId)), "5ee15f85"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?task ?taskName ?msgFlow ?sourceRef ?targetRef ?msgRef WHERE {
  ?choreo a bboExt:Choreography .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
}
LIMIT 50
